mapper.select:
SELECT /* base.sy :: SyhSendEmailLog :: selectList */ l.* , ste.site_nm AS site_nm , tpl.template_nm AS template_nm , usr.user_nm AS user_nm , cd_sr.code_label AS result_cd_nm FROM syh_send_email_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN sy_template tpl ON tpl.template_id = l.template_id LEFT JOIN sy_user usr ON usr.user_id = l.user_id LEFT JOIN sy_code cd_sr ON cd_sr.code_grp = 'SEND_RESULT' AND cd_sr.code_value = l.result_cd
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.send_date ASC ORDER BY l.send_date DESC ORDER BY l.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.sy :: SyhSendEmailLog :: selectPageList */ l.* , ste.site_nm AS site_nm , tpl.template_nm AS template_nm , usr.user_nm AS user_nm , cd_sr.code_label AS result_cd_nm FROM syh_send_email_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN sy_template tpl ON tpl.template_id = l.template_id LEFT JOIN sy_user usr ON usr.user_id = l.user_id LEFT JOIN sy_code cd_sr ON cd_sr.code_grp = 'SEND_RESULT' AND cd_sr.code_value = l.result_cd
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.send_date ASC ORDER BY l.send_date DESC ORDER BY l.reg_date DESC
LIMIT #{limit} OFFSET #{offset}
